static void cpu_components_step_post(CPUState *cpu, DecodedInstruction *inst, uint16_t pc_before) {
    (void)inst;
    (void)pc_before;
    {
        ComponentState_coco1_io *comp = &cpu->comp_coco1_io;
        cpu->active_component_id = "coco1_io";
        uint64_t now = cpu->total_cycles;
        if (comp->cart_autorun_pending != 0u) {
            /*
             * CoCo cartridge autorun approximation:
             * when a cartridge ROM is present, raise a one-shot cart interrupt
             * line edge so BASIC can jump into cartridge startup code.
             */
            if (cpu->comp_coco_cart0.rom_data != NULL && cpu->comp_coco_cart0.rom_size > 0u) {
                cpu->interrupt_vector = 0x01u;
                cpu->interrupt_pending = true;
            }
            comp->cart_autorun_pending = 0u;
        }
        uint64_t frame_tstates = (CPU_SYSTEM_CLOCK_HZ > 0u) ? (CPU_SYSTEM_CLOCK_HZ / 60u) : 14915u;
        if (frame_tstates == 0u) frame_tstates = 14915u;

        if (comp->last_cycle == 0u) {
            comp->last_cycle = now;
        }
        if (now >= comp->last_cycle) {
            comp->tstate_accum += (now - comp->last_cycle);
        }
        comp->last_cycle = now;
        if (comp->tstate_accum < frame_tstates) return;
        comp->tstate_accum -= frame_tstates;
        comp->frame_counter += 1u;

        {
            uint64_t sig_args[4] = {
                (uint64_t)comp->frame_counter,
                (uint64_t)now,
                (uint64_t)comp->sam_display_base,
                (uint64_t)(comp->sam_vdg_mode & 0x07u)
            };
            cpu_component_emit_signal(cpu, "coco1_io", "frame_ready", sig_args, 4);
        }
    }
}

