    uint16_t nn = (uint16_t)(((uint16_t)hi << 8) | (uint16_t)lo);
    uint16_t d = (uint16_t)(((uint16_t)cpu->registers[REG_A] << 8) | (uint16_t)cpu->registers[REG_B]);
    uint32_t t = (uint32_t)d + (uint32_t)nn;
